const body = $json.body || $json;

// Kapso قد يرسل data كـ array في batch، أو object، أو يرسل payload مباشر
const payload = Array.isArray(body.data) ? body.data[0] : (body.data || body);

const data = payload || {};
const key = data.key || {};
const message = data.message || {};
const conversation = data.conversation || {};

let text =
  message.conversation ||
  message.text?.body ||
  message.kapso?.content ||
  message.extendedTextMessage?.text ||
  message.imageMessage?.caption ||
  message.videoMessage?.caption ||
  conversation.kapso?.last_message_text ||
  "";

text = String(text || "").trim();

const customerJid = key.remoteJid || "";

const customerPhone =
  customerJid.replace("@s.whatsapp.net", "") ||
  message.from ||
  conversation.phone_number ||
  "";

const customerName =
  data.pushName ||
  conversation.contact_name ||
  message.username ||
  "";

const fromMe =
  key.fromMe === true ||
  message.kapso?.direction === "outbound";

const messageType =
  body.type ||
  body.event ||
  body.eventType ||
  body._kapso?.event ||
  message.type ||
  "";

const messageId =
  message.id ||
  conversation.kapso?.last_message_id ||
  body._kapso?.idempotencyKey ||
  "";

const idempotencyKey =
  body._kapso?.idempotencyKey || "";

const phoneNumberId =
  data.phone_number_id ||
  conversation.phone_number_id ||
  body.phone_number_id ||
  "";

const conversationId =
  conversation.id ||
  body.batch_info?.conversation_id ||
  "";

let orderType = "unknown";
let tableId = "";

const lowerText = text.toLowerCase();

if (
  lowerText.includes("order_type: dine_in") ||
  lowerText.includes("dine_in") ||
  lowerText.includes("داخل الكافيه")
) {
  orderType = "dine_in";
}

if (
  lowerText.includes("order_type: takeaway") ||
  lowerText.includes("takeaway") ||
  lowerText.includes("استلام")
) {
  orderType = "takeaway";
}

const tableMatch =
  text.match(/table[:\s-]*([A-Za-z0-9]+)/i) ||
  text.match(/table_id[:\s-]*([A-Za-z0-9]+)/i) ||
  text.match(/طاولة[:\s-]*([A-Za-z0-9]+)/i);

if (tableMatch) {
  tableId = tableMatch[1];
  orderType = "dine_in";
}

const orderKeywords = [
  "ابغى", "أبغى", "ابي", "أبي", "عايز", "اريد", "أريد",
  "طلب", "واحد", "اثنين", "٢", "2", "x",
  "كابتشينو", "لاتيه", "اسبريسو", "امريكانو", "ماتشا", "تيراميسو",
  "hibiscus", "cappuccino", "latte", "espresso", "americano", "matcha", "v60"
];

const isPotentialOrder = orderKeywords.some(k =>
  lowerText.includes(k.toLowerCase())
);

return [
  {
    json: {
      customer_jid: customerJid,
      customer_phone: customerPhone,
      customer_name: customerName,
      message_text: text,
      order_type: orderType,
      table_id: tableId,
      is_potential_order: isPotentialOrder,
      from_me: fromMe,
      message_type: messageType,
      message_id: messageId,
      idempotency_key: idempotencyKey,
      phone_number_id: phoneNumberId,
      conversation_id: conversationId,
      raw: body
    }
  }
];

