parameters.jsCode:
const item = $input.first().json;

// إذا كان الناتج JSON بالفعل
if (item.is_order !== undefined) {
  return [{ json: item }];
}

// إذا كان الناتج نص
let raw =
  item.text ??
  item.response?.text ??
  item.response?.generations?.[0]?.[0]?.text ??
  item.output ??
  '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw.trim();

raw = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

try {
  return [{
    json: JSON.parse(raw)
  }];
} catch (e) {
  return [{
    json: {
      is_order: false,
      items: [],
      items_text: '',
      total: 0,
      special_request: '',
      parse_error: true,
      raw_output: raw
    }
  }];
}

const orders = $input.all().map(i => i.json);

let grandTotal = 0;

let lines = orders.map((order, index) => {
  const total = Number(order.total || 0);
  grandTotal += total;

  return `طلب ${index + 1}
${order.items_text}
${order.special_request ? `ملاحظات: ${order.special_request}` : ''}
المجموع: ${total} درهم`;
});

return [
  {
    json: {
      bill_message:
`💳 ملخص الحساب

${lines.join('\n\n')}

الإجمالي الكلي: ${grandTotal} درهم

رابط الدفع:
سيتم إضافته قريباً.`
    }
  }
];
